INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6f0ba476-moex-00029', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲與乙交往多年，感情深厚，某日甲向乙提出，希望將來以結婚為前提，由甲贈與乙新臺幣（下 同）300 萬元，作為乙購買房屋之尾款。乙欣然接受，甲並於翌日匯款至乙帳戶。一年後，兩人 因故漸生嫌隙，最後甲乙二人和平分手。下列敘述，何者正確？', '["甲以將來結婚為前提，贈與乙300萬元之行為，因違反善良風俗，其贈與契約無效", "乙既然接受以結婚為前提之贈與，嗣後未履行結婚之義務，甲得訴請求乙應履行結婚之義務", "乙若未履行結婚，甲不得請求乙履行，但甲仍得撤銷該贈與，請求乙返還甲所交付之300萬元", "甲以將來結婚為前提所為之贈與行為，係屬附條件之贈與，而非附負擔之贈與契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00030', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲在自家田地栽種西瓜，但疏於澆水，將至枯死。乙見之可惜，便每日挑水澆灌，終於結成果實。 乙將該西瓜出售於丙，但甲早已將該地出售並移轉所有權登記於丁，何人得收取尚未與土地分離 之西瓜？', '["甲", "乙", "丙", "丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00031', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者非屬天然孳息？', '["果樹上之果實", "石油原油所提煉之汽油", "煤礦區所挖出之煤礦", "寵物母貓所生之小貓"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00032', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲將其A車贈與乙，該車嚴重漏油，無法行駛。下列敘述，何者錯誤？', '["若甲於贈與乙時，不知該車之狀況，且甲無保證該車之品質，則甲不須對乙負贈與物之瑕疵擔 保責任", "若甲於贈與乙時，明知該車之狀況，但對乙保證該車之品質，則甲須對乙負贈與物之瑕疵擔保 責任", "若甲於贈與乙時，不知該車之狀況，且無保證該車之品質時，則乙不得向甲請求賠償該車漏油 所生之修繕費用", "若甲於贈與乙時，不知該車之狀況，且無保證該車之品質時，則乙得向甲請求賠償該車漏油所 生之修繕費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00033', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於無因管理之敘述，何者錯誤？', '["甲見路人乙突昏倒於路旁，遂立即將乙送醫救治。甲得向乙請求償還其所支付之醫藥費", "甲見路人乙溺水後大聲呼救，遂立即下水援助。若乙猛力掙扎，甲為免同歸於盡，不得不將乙 擊昏後予以施救，甲對乙因此所生之損害不負賠償之責", "甲見路人乙在屋外引火自焚，遂立即前往滅火。若在搶救過程中，乙不斷拒絕受救，而乙手持 之名牌打火機亦在抵抗時掉落，甲對乙因此所生之損害須負賠償之責", "甲誤以為走失A犬之飼主為乙，實則為丙。若甲購買飼料一包供飢餓之A犬食用，甲得向丙請 求償還其所支付之飼料費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00034', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲營造商承攬乙機關之橋梁工程，因乙招標文件中需求書誤植結構之耐重度，造成甲建造完成之 橋梁無法供聯結車通行，以致橋梁實用性及公共利益受損。下列關於承攬之敘述，何者錯誤？', '["甲之施工錯誤乃屬不可歸責於己，甲仍得請求全部之報酬", "因完成之橋梁無法供聯結車通行，有損於通常使用之目的，乙仍不得請求甲修補該瑕疵", "若橋梁無法供聯結車通行之瑕疵不能修補時，縱不可歸責於甲之事由，乙仍得請求損害賠償", "若橋梁完工交付後，因強烈地震而震垮，乙仍須給付全部之報酬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00035', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於僱傭之敘述，依民法規定，何者錯誤？', '["受僱人未經僱用人同意，不得擅自使第三人代服勞務", "僱用人縱受領勞務遲延，受僱人仍有補服勞務之義務", "受僱人因服勞務所受之損害，如非因可歸責於自己之事由所致者，僱用人縱無過失，受僱人仍 得向僱用人請求賠償", "受僱人遵守規則行走於斑馬線上時，遭人闖紅燈撞擊，致須長期臥床休養。該僱傭縱訂有期限， 受僱人得於期滿前終止之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00036', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲與乙訂立買賣其所有之A古董花瓶之契約後，又與丙訂立A之買賣契約，並將A所有權移轉 於丙。下列敘述，何者正確？', '["基於契約自由原則，甲不須對乙負任何責任", "甲之行為害及以A為標的之乙之債權，乙得主張撤銷甲、丙間之契約", "甲處分A於丙，以致於無資力賠償對乙造成之損害時，乙得主張債權人撤銷權", "得主張債權人撤銷權之乙，直接向甲、丙表示撤銷時，即生撤銷之效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00037', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者非屬於債權讓與？', '["連帶債務人中之一人清償後，得承受債權人之權利向他債務人代位求償", "不動產買受人承擔設定於該不動產之抵押權及債務", "以遺囑將其對債務人之債權，贈與受遺贈人", "債權人透過票據貼現取得融通資金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00038', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲欠乙新臺幣100萬元，並以自己所有房屋一棟供作擔保。嗣後清償期屆至，甲仍無力償還債務， 丙因與甲素來交好，因而欲代甲清償。惟乙向來垂涎該棟房屋。下列敘述，何者正確？', '["丙欲代甲清償，乙得拒絕", "丙欲代甲清償，乙不得拒絕", "若甲對丙之代為清償表示反對之意思時，則乙不得拒絕丙之清償", "若甲對丙之代為清償表示反對之意思時，如果丙對債之履行有利害關係時，則乙得拒絕丙之清償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
